SCHEMA = {
    "name": "poison_lethal_check",
    "description": "Calculates if current poison stacks will be lethal, how many turns it will take, and the exact damage dealt over the next 1-3 turns.",
    "input_schema": {
        "type": "object",
        "properties": {
            "enemy_hp": {"type": "integer"},
            "poison_stacks": {"type": "integer"}
        },
        "required": ["enemy_hp", "poison_stacks"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(enemy_hp, poison_stacks):
    # Handle possible list bindings gracefully
    hp = enemy_hp[0] if isinstance(enemy_hp, list) and enemy_hp else (enemy_hp if isinstance(enemy_hp, int) else 0)
    p_stacks = poison_stacks[0] if isinstance(poison_stacks, list) and poison_stacks else (poison_stacks if isinstance(poison_stacks, int) else 0)

    if p_stacks <= 0:
        return {
            "is_lethal": False,
            "total_poison_potential": 0,
            "turns_to_lethal": None,
            "damage_1_turn": 0,
            "damage_2_turns": 0,
            "damage_3_turns": 0,
            "unmitigated_hp_remaining": hp
        }

    total_potential = (p_stacks * (p_stacks + 1)) // 2
    dmg_1 = p_stacks
    dmg_2 = dmg_1 + max(0, p_stacks - 1)
    dmg_3 = dmg_2 + max(0, p_stacks - 2)

    is_lethal = total_potential >= hp
    is_lethal_next_turn = dmg_1 >= hp

    turns_to_lethal = None
    if is_lethal:
        cumulative_dmg = 0
        current_p = p_stacks
        turns = 0
        while cumulative_dmg < hp and current_p > 0:
            cumulative_dmg += current_p
            current_p -= 1
            turns += 1
        turns_to_lethal = turns

    return {
        "is_lethal": is_lethal,
        "is_lethal_next_turn": is_lethal_next_turn,
        "total_poison_potential": total_potential,
        "turns_to_lethal": turns_to_lethal,
        "damage_1_turn": dmg_1,
        "damage_2_turns": dmg_2,
        "damage_3_turns": dmg_3,
        "unmitigated_hp_remaining": max(0, hp - total_potential)
    }

