SCHEMA = {
    "name": "kin_priest_focus_evaluator",
    "description": "Evaluates which target to focus in the Kin Priest boss fight based on enemy HP.",
    "input_schema": {
        "type": "object",
        "properties": {
            "enemies": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "id": {"type": "string"},
                        "current_hp": {"type": "integer"},
                        "is_minion": {"type": "boolean"}
                    }
                }
            }
        },
        "required": ["enemies"]
    }
}

APPLICABLE_STATES = ["boss"]

def execute(enemies):
    # This tool evaluates target priority for the Kin Priest fight.
    kin_followers = [e for e in enemies if "Follower" in e.get("id", "")]
    kin_priest = [e for e in enemies if "Priest" in e.get("id", "")]

    if not kin_followers and not kin_priest:
        return {"recommendation": "Not Kin Priest encounter"}

    alive_followers = [e for e in kin_followers if e["current_hp"] > 0]

    if alive_followers:
        # Sort by lowest HP to burst down
        target = min(alive_followers, key=lambda x: x["current_hp"])
        return {
            "recommendation": "FOCUS_FOLLOWERS",
            "reasoning": "Kin Followers scale Strength rapidly and deal massive combined damage. Focus them down first (they have ~60 Max HP) before targeting the Kin Priest.",
            "primary_target_id": target["id"]
        }

    return {
        "recommendation": "FOCUS_PRIEST",
        "reasoning": "All followers are dead, focus the Priest."
    }

